import { useCallback } from "react";
import { toast } from "sonner";
import { Github, Loader2 } from "lucide-react";
import { native } from "@/platform";
import { getBackendUrl } from "@/shared/config/api.config";
import { getErrorMessage } from "@shared/lib/errors";
import { RepoService } from "@/features/repository/api/repository.service";
import { WorkspaceService } from "@/features/workspace/api/workspace.service";
import { queryClient } from "@/shared/api/queryClient";
import { queryKeys } from "@/shared/api/queryKeys";
import { useCompleteOnboarding } from "../../api";

interface DeusStepProps {
  onBack: () => void;
  onComplete: () => void;
}

const REPO = {
  url: "https://github.com/zvadaadam/opendevs",
  name: "opendevs",
  displayName: "Deus",
  displayUrl: "github.com/zvadaadam/opendevs",
  description: "The source behind the tool you\u2019re using right now.",
} as const;

/**
 * Detects whether a git_clone error means the repo already exists on disk.
 *
 * git_clone returns several variants depending on the code path:
 *   - "already contains a git repository" -- .git dir found in target (pre-clone check)
 *   - "already exists and is not empty" -- non-empty target dir without .git
 *   - "already exists" -- git CLI stderr when target dir exists
 *   - "destination path ... already exists" -- another git CLI stderr variant
 */
function isAlreadyClonedError(message: string): boolean {
  return (
    message.includes("already contains") ||
    message.includes("already exists") ||
    message.includes("destination path")
  );
}

/**
 * Fire-and-forget: clone repo, register in DB, invalidate queries.
 *
 * Runs independently of React component lifecycle -- safe to call then unmount.
 * Uses only singletons: invoke, RepoService, queryClient, toast.
 * On success the repo appears in the sidebar via query invalidation.
 * On failure a toast tells the user what happened (the <Toaster> mounts
 * in App.tsx after onboarding completes, well before this async work finishes).
 */
async function cloneAndRegisterInBackground() {
  try {
    const home = await native.dialog.getHomeDir();
    const target = `${home}/Developer/${REPO.name}`;

    // Phase 1: Clone (or detect already-cloned)
    let alreadyCloned = false;
    try {
      const baseUrl = await getBackendUrl();
      const res = await fetch(`${baseUrl}/api/repos/clone`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ url: REPO.url, targetPath: target }),
      });
      if (!res.ok) {
        const err = await res.json().catch(() => ({ error: "Clone failed" }));
        throw new Error(err.error || `HTTP ${res.status}`);
      }
    } catch (err) {
      const message = getErrorMessage(err);
      if (!isAlreadyClonedError(message)) {
        console.error("[Deus] Clone failed:", message);
        toast.error("Couldn\u2019t clone Deus. You can add it later from the sidebar.");
        return;
      }
      alreadyCloned = true;
    }

    // Phase 2: Register in DB (idempotent -- 409 = already registered)
    let repoId: string | null = null;
    try {
      const repo = await RepoService.add(target);
      repoId = repo.id;
    } catch (err) {
      // ApiError shape from client.ts: { status, message, details: <response body> }
      // 409 response body: { error: "...", details: { id, name, ... } }
      const apiErr = err as { status?: number; details?: { details?: unknown } };
      if (apiErr?.status === 409) {
        const existing = apiErr.details?.details;
        if (existing && typeof existing === "object" && "id" in existing) {
          repoId = (existing as { id: string }).id;
        }
        if (!repoId) {
          console.warn("[Deus] 409 conflict but couldn't extract repo ID:", err);
        }
      } else {
        console.error("[Deus] Register failed:", err);
        toast.error(
          'Deus cloned but couldn\u2019t register. Use "Add Repository" in the sidebar.'
        );
        return;
      }
    }

    // Phase 3: Create workspace so repo appears in the sidebar.
    // The sidebar only shows repos that have at least one workspace.
    if (repoId) {
      try {
        await WorkspaceService.create(repoId);
      } catch {
        // Workspace creation failed -- repo is registered, user can create manually.
        // Don't block the success toast; the repo exists and can be used.
        console.warn("[Deus] Workspace creation failed, repo still registered");
      }
    }

    // Phase 4: Refresh sidebar so the new repo + workspace appear
    queryClient.invalidateQueries({ queryKey: queryKeys.repos.all });
    queryClient.invalidateQueries({ queryKey: queryKeys.workspaces.all });

    toast.success(alreadyCloned ? "Deus repository added" : "Deus cloned and ready");
  } catch (err) {
    console.error("[Deus] Background clone error:", err);
    toast.error("Something went wrong cloning Deus.");
  }
}

export function DeusStep({ onBack, onComplete }: DeusStepProps) {
  const completeMutation = useCompleteOnboarding();

  /**
   * Fire-and-forget: kick off clone pipeline as a detached promise,
   * then immediately complete onboarding. The user lands in the app
   * and the repo appears in the sidebar once cloneAndRegisterInBackground
   * finishes and invalidates the query cache.
   */
  const handleCloneAndFinish = useCallback(async () => {
    // Launch background pipeline -- intentionally not awaited.
    // Uses zero React state; completes independently of component lifecycle.
    cloneAndRegisterInBackground();

    // Complete onboarding immediately. If this fails (unlikely -- it's
    // just a settings write), TanStack Query's built-in retry handles it.
    await completeMutation.mutateAsync();
    onComplete();
  }, [completeMutation, onComplete]);

  const handleSkip = useCallback(async () => {
    await completeMutation.mutateAsync();
    onComplete();
  }, [completeMutation, onComplete]);

  return (
    <div className="flex w-full max-w-md flex-col gap-6">
      {/* Badge */}
      <span className="text-2xs font-medium tracking-wider text-white/30 uppercase">
        Community Built
      </span>

      {/* Header */}
      <div className="-mt-4 space-y-2">
        <h2 className="text-2xl font-semibold text-white">Shape Deus with us</h2>
        <p className="text-sm text-white/50">
          Deus is built by the people who use it. Clone the source, send a PR, or share an idea.
          You have the power to shape it.
        </p>
      </div>

      {/* Repo card */}
      <div className="flex items-center gap-3 rounded-xl bg-white/[0.04] p-4">
        <div className="flex h-10 w-10 shrink-0 items-center justify-center rounded-lg bg-white/[0.08]">
          <Github className="h-4.5 w-4.5 text-white/40" />
        </div>

        <div className="min-w-0 flex-1">
          <p className="truncate text-sm font-medium text-white">{REPO.displayName}</p>
          <p className="truncate font-mono text-xs text-white/30">{REPO.displayUrl}</p>
        </div>
      </div>

      {/* Description line */}
      <p className="text-xs text-white/40 italic">{REPO.description}</p>

      {/* Spacer -- matches previous layout height for progress area */}
      <div className="min-h-[28px]" />

      {/* Footer */}
      <div className="flex items-center gap-3 pt-2">
        <button
          onClick={onBack}
          disabled={completeMutation.isPending}
          className="rounded-xl px-6 py-2.5 text-sm font-medium text-white/50 transition-colors duration-200 hover:text-white/80 disabled:opacity-50"
        >
          Back
        </button>
        <div className="flex-1" />

        <button
          onClick={handleSkip}
          disabled={completeMutation.isPending}
          className="rounded-xl bg-white/10 px-6 py-2.5 text-sm font-medium text-white/70 transition-colors duration-200 hover:bg-white/15 hover:text-white disabled:opacity-50"
        >
          Skip
        </button>

        <button
          onClick={handleCloneAndFinish}
          disabled={completeMutation.isPending}
          className="rounded-xl bg-white px-6 py-2.5 text-sm font-semibold text-black transition-transform duration-200 hover:scale-[1.02] active:scale-[0.98] disabled:opacity-50"
        >
          {completeMutation.isPending ? (
            <Loader2 className="h-4 w-4 animate-spin" />
          ) : (
            "Clone & Continue"
          )}
        </button>
      </div>
    </div>
  );
}

import { useMemo } from "react";
import { Plus, ChevronRight, ChevronDown, GitPullRequest } from "lucide-react";
import { AnimatePresence, m, useReducedMotion } from "framer-motion";
import { SidebarMenuItem } from "@/components/ui/sidebar";
import { Collapsible, CollapsibleTrigger } from "@/components/ui/collapsible";
import { Tooltip, TooltipTrigger, TooltipContent } from "@/components/ui/tooltip";
import { cn } from "@/shared/lib/utils";
import { useUnreadStore } from "@/features/session/store/unreadStore";
import { useWorkspaceLayoutStore } from "@/features/workspace/store/workspaceLayoutStore";
import { getCleanRepoName, splitByRecency } from "../lib/utils";
import { sortByStatusPriority } from "../lib/status";
import { useSidebarStore } from "../store/sidebarStore";
import type { RepositoryItemProps } from "../model/types";
import type { Workspace, DiffStats, RepoGroup } from "@/shared/types";
import type { WorkspaceStatus } from "@shared/enums";
import { WorkspaceItem } from "./WorkspaceItem";
import { RepoAvatar } from "./RepoAvatar";
import { SidebarRow, SidebarRowMain, SidebarRowIconSlot, SidebarRowRight } from "./SidebarRow";
import { DeusRepositoryBanner } from "./DeusRepositoryBanner";

/** Check if a git remote URL points to GitHub */
function isGitHubUrl(url: string | null | undefined): boolean {
  return !!url && url.includes("github.com");
}

/**
 * RepositoryItem — V2: Jony Ive
 *
 * Layout:
 *   [Badge 20×20] [RepoName]  ...  [PR] [+] [⋯]  (hover-reveal actions)
 *     └── [+ New workspace]
 *     └── WorkspaceItem[]
 *
 * The repo header uses text-secondary (B0B0B0) 14px medium.
 * Action icons: text-muted (#787878), appear on hover.
 */
export function RepositoryItem({
  repository,
  isCollapsed,
  selectedWorkspaceId,
  onToggleCollapse,
  onWorkspaceClick,
  onNewWorkspace,
  onNewWorkspaceFromGitHub,
  onArchive,
  onStatusChange,
  diffStatsMap,
  sidebarExpanded,
}: RepositoryItemProps) {
  const reduceMotion = useReducedMotion();
  const repoName = getCleanRepoName(repository.repo_name);

  // Build set of workspace IDs that have any unread tab session,
  // checking all tab sessions (matching WorkspaceItem's logic).
  const unreadMap = useUnreadStore((s) => s.unreadSessionIds);
  const layouts = useWorkspaceLayoutStore((s) => s.layouts);
  const unreadWorkspaceIds = useMemo(() => {
    const ids = new Set<string>();
    for (const ws of repository.workspaces) {
      const tabIds = layouts[ws.id]?.chatTabSessionIds;
      const sessionIds = tabIds?.length
        ? tabIds
        : ws.current_session_id
          ? [ws.current_session_id]
          : [];
      if (sessionIds.some((sid) => unreadMap[sid])) ids.add(ws.id);
    }
    return ids.size > 0 ? ids : undefined;
  }, [repository.workspaces, unreadMap, layouts]);
  // Detect the deus repo by clean name (GitHub repo is still "opendevs")
  const isDeus = repoName === "opendevs";
  const workspaceCount = repository.workspaces.filter((w) => w.state !== "archived").length;

  return (
    <Collapsible open={!isCollapsed} onOpenChange={() => onToggleCollapse()}>
      <SidebarMenuItem
        data-state={isCollapsed ? "closed" : "open"}
        className="group/repository-item relative"
      >
        <CollapsibleTrigger asChild>
          <SidebarRow
            variant="repo"
            role="button"
            aria-label={`Toggle ${repoName} workspaces`}
            className="cursor-grab"
          >
            <SidebarRowMain className="gap-2">
              <div className="relative flex-shrink-0">
                <div className="transition-opacity duration-150 group-hover/repository-item:opacity-0">
                  <RepoAvatar repoName={repository.repo_name} />
                </div>
                <ChevronRight
                  className={cn(
                    "absolute inset-0 m-auto h-4 w-4",
                    "text-text-muted opacity-0 transition-[transform,opacity] duration-150 group-hover/repository-item:opacity-100",
                    !isCollapsed && "rotate-90"
                  )}
                />
              </div>
              <span className="text-text-secondary truncate text-sm font-medium">{repoName}</span>
              {workspaceCount > 0 && (
                <span className="text-text-muted text-xs tabular-nums">{workspaceCount}</span>
              )}
            </SidebarRowMain>
            {sidebarExpanded && (
              <SidebarRowRight className="gap-2 opacity-0 transition-opacity duration-150 group-hover/repository-item:opacity-100">
                {isGitHubUrl(repository.git_origin_url) && onNewWorkspaceFromGitHub && (
                  <Tooltip>
                    <TooltipTrigger asChild>
                      <button
                        type="button"
                        aria-label={`New workspace from PR or branch in ${repoName}`}
                        onClick={(e) => {
                          e.stopPropagation();
                          onNewWorkspaceFromGitHub(repository.repo_id);
                        }}
                        className="text-text-muted hover:text-text-tertiary cursor-pointer [&_*]:cursor-pointer"
                      >
                        <GitPullRequest className="h-4 w-4" />
                      </button>
                    </TooltipTrigger>
                    <TooltipContent side="bottom">New from PR or branch</TooltipContent>
                  </Tooltip>
                )}
                <Tooltip>
                  <TooltipTrigger asChild>
                    <button
                      type="button"
                      aria-label={`New workspace in ${repoName}`}
                      onClick={(e) => {
                        e.stopPropagation();
                        onNewWorkspace(repository.repo_id);
                      }}
                      className="text-text-muted hover:text-text-tertiary cursor-pointer [&_*]:cursor-pointer"
                    >
                      <Plus className="h-4 w-4" />
                    </button>
                  </TooltipTrigger>
                  <TooltipContent side="bottom">New workspace</TooltipContent>
                </Tooltip>
              </SidebarRowRight>
            )}
          </SidebarRow>
        </CollapsibleTrigger>
      </SidebarMenuItem>
      <AnimatePresence initial={false}>
        {!isCollapsed && (
          <m.ul
            key="workspace-list"
            initial={reduceMotion ? false : { height: 0, opacity: 0 }}
            animate={{ height: "auto", opacity: 1 }}
            exit={reduceMotion ? { opacity: 0 } : { height: 0, opacity: 0 }}
            transition={{ duration: 0.22, ease: [0.165, 0.84, 0.44, 1] }}
            className="flex min-w-0 flex-col overflow-hidden"
          >
            {sidebarExpanded && (
              <RepositoryWorkspaceList
                repository={repository}
                isDeus={isDeus}
                selectedWorkspaceId={selectedWorkspaceId}
                unreadWorkspaceIds={unreadWorkspaceIds}
                diffStatsMap={diffStatsMap}
                reduceMotion={reduceMotion}
                onNewWorkspace={onNewWorkspace}
                onWorkspaceClick={onWorkspaceClick}
                onArchive={onArchive}
                onStatusChange={onStatusChange}
              />
            )}
          </m.ul>
        )}
      </AnimatePresence>
    </Collapsible>
  );
}

// ── Inner list with stale-workspace collapsing ───────────────────────────

interface RepositoryWorkspaceListProps {
  repository: RepoGroup;
  isDeus: boolean;
  selectedWorkspaceId: string | null;
  unreadWorkspaceIds?: Set<string>;
  diffStatsMap?: Record<string, DiffStats>;
  reduceMotion: boolean | null;
  onNewWorkspace: (repoId?: string) => void;
  onWorkspaceClick: (workspace: Workspace) => void;
  onArchive?: (workspaceId: string) => void;
  onStatusChange?: (workspaceId: string, status: WorkspaceStatus) => void;
}

function RepositoryWorkspaceList({
  repository,
  isDeus,
  selectedWorkspaceId,
  unreadWorkspaceIds,
  diffStatsMap,
  reduceMotion,
  onNewWorkspace,
  onWorkspaceClick,
  onArchive,
  onStatusChange,
}: RepositoryWorkspaceListProps) {
  const isExpanded = useSidebarStore((s) => s.expandedOldWorkspaces.has(repository.repo_id));
  const toggleOldWorkspaces = useSidebarStore((s) => s.toggleOldWorkspaces);

  const sortedWorkspaces = sortByStatusPriority(
    repository.workspaces.filter((w) => w.state !== "archived"),
    unreadWorkspaceIds
  );

  const [visible, stale] = splitByRecency(sortedWorkspaces, selectedWorkspaceId);
  const hasStale = stale.length > 0;
  const displayedWorkspaces = hasStale && !isExpanded ? visible : sortedWorkspaces;

  return (
    <>
      {isDeus && (
        <m.li
          initial={reduceMotion ? false : { opacity: 0, y: -4 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{
            duration: 0.22,
            ease: [0.165, 0.84, 0.44, 1],
            delay: reduceMotion ? 0 : 0.02,
          }}
        >
          <DeusRepositoryBanner onNewWorkspace={() => onNewWorkspace(repository.repo_id)} />
        </m.li>
      )}

      {sortedWorkspaces.length === 0 && (
        <m.li
          initial={reduceMotion ? false : { opacity: 0, y: -4 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{
            duration: 0.18,
            ease: [0.165, 0.84, 0.44, 1],
            delay: reduceMotion ? 0 : 0.03,
          }}
        >
          <SidebarRow
            variant="action"
            asChild
            onClick={() => onNewWorkspace(repository.repo_id)}
            className="text-text-tertiary hover:text-text-secondary w-full text-left text-base"
          >
            <button type="button">
              <SidebarRowMain>
                <SidebarRowIconSlot>
                  <Plus className="h-4 w-4" />
                </SidebarRowIconSlot>
                <span className="font-normal">New workspace</span>
              </SidebarRowMain>
            </button>
          </SidebarRow>
        </m.li>
      )}

      {displayedWorkspaces.map((workspace, index) => (
        <m.li
          key={workspace.id}
          initial={reduceMotion ? false : { opacity: 0, y: -4 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{
            duration: 0.18,
            ease: [0.165, 0.84, 0.44, 1],
            delay: reduceMotion ? 0 : Math.min(0.05 + index * 0.025, 0.12),
          }}
        >
          <WorkspaceItem
            workspace={workspace}
            isActive={workspace.id === selectedWorkspaceId}
            diffStats={diffStatsMap?.[workspace.id]}
            onClick={onWorkspaceClick}
            onArchive={onArchive}
            onStatusChange={onStatusChange}
          />
        </m.li>
      ))}

      {hasStale && (
        <m.li
          initial={reduceMotion ? false : { opacity: 0 }}
          animate={{ opacity: 1 }}
          transition={{ duration: 0.15, ease: [0.165, 0.84, 0.44, 1] }}
        >
          <SidebarRow
            variant="action"
            asChild
            className="text-text-muted hover:text-text-secondary w-full text-left"
          >
            <button type="button" onClick={() => toggleOldWorkspaces(repository.repo_id)}>
              <SidebarRowMain>
                <SidebarRowIconSlot>
                  <ChevronDown
                    className={cn(
                      "h-3.5 w-3.5 transition-transform duration-150",
                      isExpanded && "rotate-180"
                    )}
                  />
                </SidebarRowIconSlot>
                <span className="text-xs font-medium">
                  {isExpanded ? "Show less" : `Show ${stale.length} more`}
                </span>
              </SidebarRowMain>
            </button>
          </SidebarRow>
        </m.li>
      )}
    </>
  );
}

import { Loader2 } from "lucide-react";
import { cn } from "@/shared/lib/utils";
import { match } from "ts-pattern";
import { getCleanRepoName } from "@/features/sidebar/lib/utils";
import { DeusEmptyState } from "./DeusEmptyState";

interface WorkspaceEmptyStateProps {
  repoName?: string | null;
  parentBranch?: string | null;
  /** True when this workspace has never had any messages — show full onboarding */
  isFirstSession?: boolean;
  /** Workspace is still being set up — show spinner + step text instead of "ready" */
  initializing?: boolean;
  /** Current init pipeline step (worktree, dependencies, hooks, session) */
  initStep?: string | null;
  className?: string;
}

const STEPS = [
  { num: 1, label: "Build with AI" },
  { num: 2, label: "Review the diff" },
  { num: 3, label: "Open a pull request" },
] as const;

/**
 * Builds an educational subtitle that teaches git concepts through plain language:
 * - "branched from" introduces the concept of branching
 * - the parent branch name appears naturally without explanation
 */
function subtitle(repoName?: string | null, parentBranch?: string | null): string {
  const project = repoName ?? "your project";
  if (parentBranch) {
    return `A safe copy of ${project}, branched from ${parentBranch}.`;
  }
  return `A safe copy of ${project}.`;
}

export function WorkspaceEmptyState({
  repoName,
  parentBranch,
  isFirstSession = false,
  initializing = false,
  initStep,
  className,
}: WorkspaceEmptyStateProps) {
  // New tab in active workspace — minimal prompt
  if (!isFirstSession) {
    return (
      <div
        className={cn(
          "animate-fade-in-up flex h-full flex-col items-center justify-center",
          className
        )}
      >
        <p className="text-muted-foreground/50 text-sm">What would you like to work on?</p>
      </div>
    );
  }

  // Deus repo: the user is working on the IDE itself — show a special state
  const cleanRepoName = repoName ? getCleanRepoName(repoName) : repoName;
  if (cleanRepoName === "opendevs") {
    return <DeusEmptyState parentBranch={parentBranch} className={className} />;
  }

  // Fresh workspace — clean, confident, centered
  return (
    <div
      className={cn(
        "animate-fade-in-up flex h-full flex-col items-center justify-center",
        className
      )}
    >
      <div className="flex flex-col items-center gap-5">
        <div className="text-center">
          <h2 className="text-muted-foreground/60 flex items-center justify-center gap-2 text-xs font-semibold tracking-wide uppercase">
            {initializing && <Loader2 className="h-3.5 w-3.5 animate-spin" />}
            {initializing
              ? match(initStep)
                  .with("worktree", () => "Creating worktree...")
                  .with("dependencies", () => "Installing dependencies...")
                  .with("hooks", () => "Setting up environment...")
                  .with("session", () => "Finalizing...")
                  .otherwise(() => "Setting up workspace...")
              : "Workspace ready"}
          </h2>
          {!initializing && (
            <p className="text-muted-foreground/45 mt-1.5 text-sm">
              {subtitle(repoName, parentBranch)}
            </p>
          )}
        </div>

        <div className="flex items-baseline gap-6">
          {STEPS.map((step) => (
            <div key={step.num} className="flex items-baseline gap-1.5">
              <span className="text-muted-foreground/30 font-mono text-xs font-medium">
                {String(step.num).padStart(2, "0")}
              </span>
              <span className="text-muted-foreground/50 text-sm">{step.label}</span>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

